import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"Challenge Stages","description":"","frontmatter":{},"headers":[],"relativePath":"en/stages/challenge.md","filePath":"en/stages/challenge.md","lastUpdated":1775394001000}'),s={name:"en/stages/challenge.md"};function l(i,t,n,o,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="challenge-stages" tabindex="-1">Challenge Stages <a class="header-anchor" href="#challenge-stages" aria-label="Permalink to &quot;Challenge Stages&quot;">​</a></h1><p>Challenge stages are high-difficulty encounters in Morimens that test your team-building and combat skills. They offer premium rewards not available in regular stages.</p><h2 id="challenge-modes" tabindex="-1">Challenge Modes <a class="header-anchor" href="#challenge-modes" aria-label="Permalink to &quot;Challenge Modes&quot;">​</a></h2><h3 id="erosion-disaster-zone-dissolution-zone" tabindex="-1">Erosion Disaster Zone (Dissolution Zone) <a class="header-anchor" href="#erosion-disaster-zone-dissolution-zone" aria-label="Permalink to &quot;Erosion Disaster Zone (Dissolution Zone)&quot;">​</a></h3><p>The primary endgame multi-team challenge mode. Requires non-repeating Awakeners, Wheels, and Key Orders across teams.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Details</th></tr></thead><tbody><tr><td>Type</td><td>High-difficulty endgame challenge</td></tr><tr><td>Reset</td><td>Every 2 weeks, Thursday 15:00</td></tr><tr><td>Unlock</td><td>Clear Main Story 4-3 (originally 5-4, lowered in v1.2)</td></tr><tr><td>Key Reward</td><td>Black Tribute, Primordial Spirit Core, Spirit Core Shards</td></tr><tr><td>Restriction</td><td>Cannot reuse the same Awakener, Wheel of Destiny, or Key Order across teams</td></tr></tbody></table><p><strong>Alert Levels:</strong></p><table tabindex="0"><thead><tr><th>Alert Level</th><th>Training Values</th><th>Enemy Level</th><th>Notes</th></tr></thead><tbody><tr><td>I</td><td>50, 55, 60, 65, 70</td><td>50-58</td><td>Entry level</td></tr><tr><td>II</td><td>55, 60, 65, 70, 75</td><td>55-63</td><td>Moderate difficulty</td></tr><tr><td>III</td><td>60, 65, 70, 75, 80</td><td>60-68</td><td>Affected by Erosion Black Tide debuffs</td></tr></tbody></table><p><strong>Erosion Black Tide Debuffs (Level III):</strong></p><table tabindex="0"><thead><tr><th>Debuff</th><th>Effect</th></tr></thead><tbody><tr><td>Aliemus Decay</td><td>Reduces Aliemus acquisition</td></tr><tr><td>Silver Key Oscillation</td><td>Disrupts Silver Key energy</td></tr><tr><td>Raging Seas</td><td>Deep Sea realm special effect</td></tr><tr><td>Scarlet Nurturing</td><td>Caro realm special effect</td></tr><tr><td>Realm&#39;s End</td><td>Ultra realm special effect</td></tr><tr><td>From Oblivion</td><td>Chaos realm special effect</td></tr></tbody></table><p><strong>Reward Thresholds:</strong> 50, 100, 150, 225, 300, 305, 310, 315, 320, 325, 330, 335, 340, 345, 350</p><p>At 300+ training value: Black Tribute x2,500 + Rose Scrip x100,000 per tier.</p><h3 id="phantasmal-dive-dream-dive" tabindex="-1">Phantasmal Dive (Dream Dive) <a class="header-anchor" href="#phantasmal-dive-dream-dive" aria-label="Permalink to &quot;Phantasmal Dive (Dream Dive)&quot;">​</a></h3><p>A roguelike ranked mode with a tier system. Significantly overhauled in v1.5.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Details</th></tr></thead><tbody><tr><td>Type</td><td>Roguelike ranked mode</td></tr><tr><td>Reset</td><td>Weekly</td></tr><tr><td>Drops</td><td>D-Jewels (Erosion Pearls), Silver</td></tr><tr><td>D-Jewel Formula</td><td>(Phantasmal level + 2) x 100</td></tr><tr><td>Ranking</td><td>Tier-based (up to Phantasmal Legend), with weekly settlement</td></tr></tbody></table><p><strong>Roguelike Mechanics:</strong></p><ul><li><strong>Map</strong>: Fog-of-war hex grid map, changes daily. Node types: Battle / Elite / Boss / Shop / Rest / Random Event / Treasure.</li><li><strong>Inscriptions</strong>: Obtained after defeating normal enemies (3-choose-1). Priority: Masterstroke &gt; Inspiration &gt; AP &gt; Mirror Partner &gt; Recall.</li><li><strong>Creations (Artifacts)</strong>: Obtained after defeating elite enemies (3-choose-1, usually 2 negative + 1 positive). Tiers: Silver (weak, purchasable), Gold (strong, purchasable), Cursed (strong + drawback, elite/event only). Priority: AP creations &gt; Aliemus &gt; Crit Rate &gt; Card Draw &gt; Tentacle Cap.</li><li><strong>Black Ink</strong>: Drops from battles, spent at Erosion Points. Silver creation ~50 ink, Gold ~90 ink. Spending priority: Creation &gt; Awakening &gt; Normal Inscription.</li></ul><p><strong>Shop Items:</strong></p><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th></tr></thead><tbody><tr><td>Memory Quill</td><td>800 D-Jewels = 5/week</td></tr><tr><td>Shattered Remnant Dream</td><td>100 D-Jewels/week</td></tr><tr><td>Stellar Remnant Dream</td><td>25 D-Jewels/week</td></tr></tbody></table><h3 id="phase-chess-pvp" tabindex="-1">Phase Chess (PVP) <a class="header-anchor" href="#phase-chess-pvp" aria-label="Permalink to &quot;Phase Chess (PVP)&quot;">​</a></h3><p>Card-based PVP combat mode, still in Beta.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Details</th></tr></thead><tbody><tr><td>Type</td><td>PVP ranked mode</td></tr><tr><td>Reset</td><td>Weekly</td></tr><tr><td>Unlock</td><td>Clear Main Story 3-2</td></tr><tr><td>Drops</td><td>Drill Badges, Rose Scrip</td></tr><tr><td>Key Rule</td><td>Character training does not affect PVP -- all cards are at equal strength</td></tr></tbody></table><p><strong>PVP vs PVE Differences:</strong></p><table tabindex="0"><thead><tr><th>Aspect</th><th>PVE</th><th>PVP</th></tr></thead><tbody><tr><td>Hand Retention</td><td>Discard at turn end</td><td>Cards carry over</td></tr><tr><td>Draw Count</td><td>4 cards</td><td>5 cards</td></tr><tr><td>Starting AP</td><td>Fixed 5</td><td>Starts at 3, +1/turn to cap 10</td></tr><tr><td>Progression</td><td>Character levels matter</td><td>All cards equal strength</td></tr><tr><td>Dead Ally Cards</td><td>Removed</td><td>Become &quot;Teardrop&quot; (0 cost, restore 10 energy)</td></tr></tbody></table><p><strong>Death Duel</strong>: When both players reach 10 AP cap, automatically applied. Layer 1 reduces healing/shields; Layer 2 sets all healing/shields to 1 -- forcing a winner.</p><h3 id="other-challenge-modes" tabindex="-1">Other Challenge Modes <a class="header-anchor" href="#other-challenge-modes" aria-label="Permalink to &quot;Other Challenge Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Type</th><th>Drops</th><th>Description</th></tr></thead><tbody><tr><td>Lightless Realm</td><td>Star Upgrade Challenge</td><td>Lightless Currency</td><td>Unlocks Awakener star upgrades (2/3/4/5 stars). Also unlockable via Main Story 2-5.</td></tr><tr><td>D-Effect Zone</td><td>Challenge Dungeon</td><td>Lightless Currency</td><td>Additional Lightless Currency source.</td></tr><tr><td>Arcane Dominion</td><td>Challenge Dungeon</td><td>Investigation Badge</td><td>Investigation Badge acquisition.</td></tr><tr><td>Under the Outer Sky</td><td>New Dungeon</td><td>Various</td><td>v2.0+ new dungeon mode.</td></tr><tr><td>Door of All Things</td><td>Limited-Time Event</td><td>Wheel &quot;Gate of Truth&quot;, exclusive avatar</td><td>Limited event. Owning Tawil / Wheel Unseen / Gate of Truth improves efficiency.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Challenge stages are the best source of rare materials like Primordial Spirit Cores and Black Tribute. Clear the Dissolution Zone bi-weekly and Phantasmal Dive weekly for optimal progression.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Dissolution Zone has limited attempts per reset cycle. Do not waste attempts on underprepared teams. Practice in regular stages first.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Stages Overview</a></li><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li><li><a href="./../engravings/">Engravings</a></li></ul>',31)])])}const m=e(s,[["render",l]]);export{p as __pageData,m as default};
